const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, M, Z, L, R, B] = readline().split(' ').map(Number);
    let total_seats = N * M;
    let assigned_seats = 0;
    assigned_seats += B;
    assigned_seats += Math.min(L, total_seats - assigned_seats);
    assigned_seats += Math.min(R, total_seats - assigned_seats);
    assigned_seats += Math.min(Z, total_seats - assigned_seats);
    console.log(assigned_seats);
}
